// ECS Task Definition — defines what to run
// Registered via: aws ecs register-task-definition --cli-input-json file://task-def.json
{
  "family": "devlearner-api",
  "networkMode": "awsvpc",        // Required for Fargate — each task gets own ENI
  "requiresCompatibilities": ["FARGATE"],
  "cpu": "512",                   // 0.5 vCPU
  "memory": "1024",              // 1 GB
  "executionRoleArn": "arn:aws:iam::123:role/ecsTaskExecutionRole",
  // ^ Allows ECS to pull image from ECR and write logs to CloudWatch
  "taskRoleArn": "arn:aws:iam::123:role/devlearner-api-role",
  // ^ Permissions for the app itself (DynamoDB, S3, etc.)
  "containerDefinitions": [
    {
      "name": "api",
      "image": "123456789012.dkr.ecr.us-east-1.amazonaws.com/devlearner-api:v1.2.3",
      "portMappings": [
        {"containerPort": 8080, "protocol": "tcp"}
      ],
      "environment": [
        {"name": "SPRING_PROFILES_ACTIVE", "value": "prod"},
        {"name": "DB_HOST", "value": "prod-mysql.abc.us-east-1.rds.amazonaws.com"}
      ],
      "secrets": [
        // Never plaintext — ECS fetches from Secrets Manager at startup
        {"name": "DB_PASSWORD", "valueFrom": "arn:aws:secretsmanager:us-east-1:123:secret:/prod/db-password"},
        {"name": "JWT_SECRET",   "valueFrom": "arn:aws:secretsmanager:us-east-1:123:secret:/prod/jwt-secret"}
      ],
      "logConfiguration": {
        "logDriver": "awslogs",
        "options": {
          "awslogs-group": "/ecs/devlearner-api",
          "awslogs-region": "us-east-1",
          "awslogs-stream-prefix": "ecs"
        }
      },
      "healthCheck": {
        "command": ["CMD-SHELL", "curl -f http://localhost:8080/actuator/health || exit 1"],
        "interval": 30,
        "timeout": 5,
        "retries": 3,
        "startPeriod": 60  // Grace period — Spring Boot needs ~30s to start
      },
      "essential": true   // If this container dies, kill the whole task
    }
  ]
}
